using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 removed Cosmos DB indexing support (HasIndex throws).
            // Indexes must be configured directly in Cosmos DB via the Azure Portal or SDK.

            // Breaking change 2: EF 9 renamed the discriminator property from "Discriminator"
            // to "$type". Existing documents still use "Discriminator", so we must opt back in.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 3: EF 9 changed the id format from "EntityType|KeyValue"
            // to just "KeyValue". Existing documents use the old format, so we preserve it.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }
}

// Generates ids in the legacy "Blog|{key}" format to match existing documents.
class LegacyCosmosIdGenerator : Microsoft.EntityFrameworkCore.ValueGeneration.ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(Microsoft.EntityFrameworkCore.ChangeTracking.EntityEntry entry)
        => $"Blog|{Guid.NewGuid()}";
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

