        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();

        // Breaking change 5: Any raw SQL referencing "Discriminator" must be updated
        // to match the property name configured in OnModelCreating.
        // Old:  SELECT * FROM c WHERE c.Discriminator = 'Blog'
        // This still works because we kept "Discriminator" via HasDiscriminator above.
        // If you had NOT applied that fix, you'd need:
        //   SELECT * FROM c WHERE c["$type"] = 'Blog'
    }
}

